console.log("[Spect] Activador de espectador cargado");

game.renderScene = function () {
    const gameCanvas = document.querySelector("canvas");
    if (gameCanvas && this.camera) {
        gameCanvas.style.transform = `translate(${-this.camera.x}px, ${-this.camera.y}px)`;
    }
};

game.startSpect = function () {
    this.setIntroUIVisible(false);
    this.setUIVisible(true);
    this.isSpectator = true;
    this.doAutoLogin = false;
    this.hasJoined = false;

    this.camera = { x: 0, y: 0 };

    console.log("🎥 Modo espectador activado");
    this.enableFreeCamera();
};

game.enableFreeCamera = function () {
    const margin = 100;
    const speed = 30;
    const self = this; // ← guardamos una referencia a `game`

    document.addEventListener("mousemove", function (ev) {
        if (!self.isSpectator || !self.camera) return;

        // Movimiento horizontal
        if (ev.clientX < margin) {
            self.camera.x -= speed;
        } else if (ev.clientX > window.innerWidth - margin) {
            self.camera.x += speed;
        }

        // Movimiento vertical
        if (ev.clientY < margin) {
            self.camera.y -= speed;
        } else if (ev.clientY > window.innerHeight - margin) {
            self.camera.y += speed;
        }

        // Asegurar que renderScene exista
        if (typeof self.renderScene === "function") {
            self.renderScene(); // ← esto no daba error porque `this` apuntaba mal
        } else {
            console.warn("⚠️ self.renderScene no está definido");
        }
    });

    console.log("🎮 Cámara libre activada");
};

const offlineButton = document.getElementById("offlineButton");
const startButton = document.getElementById("startButton");
const areas = document.getElementById("areas");
const rooms = document.getElementById("rooms");

const offlineMapConfig = {
    cellWidth: 1280,
    currentTilemap: "tileMap.tmx",
    desirablePlayerNum: 25,
    fieldType: 0,
    hasIndicator: false,
    hasSlowFactor: false,
    height: 6400,
    isPriority: true,
    width: 6400,

    config: {
        backgroundColor: 13487565,
        defaultHeight: 995,
        defaultJoySplitRatio: 1.2,
        defaultWidth: 1855,
        loginTimeout: 90,
        serverUpdatePeriodInSecs: 60,
        viewScale: 0.69,
        grid: {
            borderColor: 7829367,
            borderSize: 5,
            lineColor: 11447982,
            lineSize: 4,
            miniGridWidth: 200
        }
    }
};

offlineButton.addEventListener("click", function () {
    // 1. Ocultar el botón Offline
    offlineButton.style.display = "none";

    

    // 3. Modificar selects
    areas.innerHTML = '<option value="Offline" selected>Offline</option>';

    // 4. Simular salas locales
    const offlineRooms = [
       "Large 1 ", "Large 2", "Sparse", "Small 1", "Small 2", "Narwhale Ball!",
       "Narwhale Egg Hunt!", "Narwhale Deathmatch"
        ];

    rooms.innerHTML = "";
    offlineRooms.forEach((roomName, index) => {
        const opt = document.createElement("option");
        opt.value = `Offline${index}`;
        opt.textContent = `${roomName} (Offline)`;
        rooms.appendChild(opt);
        areas.innerHTML = ""; // limpiar opciones anteriores correctamente
const offlineOption = document.createElement("option");
offlineOption.value = "Offline";
offlineOption.selected = true;
offlineOption.textContent = "Offline";
areas.appendChild(offlineOption);

    });

    // 5. Cambiar botón de "Play"
    startButton.textContent = "Play Offline";
    startButton.onclick = function () {
        game.startOfflineMatch(); // Esto es tu lógica del juego sin red
    };

    // 6. Evento de QUIT
    quitButton.addEventListener("click", function () {
        // Restaurar todo
        offlineButton.style.display = "block";
        quitButton.remove();

        startButton.textContent = "Play";
        startButton.onclick = function () {
            game.tryStart2(false);
        };

        // Restaurar selects originales (puede ser una función si querés modularizarlo)
        window.location.reload();// O podés regenerar con código si no querés recargar
    });
});

game.startOfflineMatch = function () {
    this.setIntroUIVisible(false);
    this.setUIVisible(true);
    this.isSpectator = false;
    this.doAutoLogin = false;
    this.hasJoined = true;

    // Acá podés setear lo que quieras como sala seleccionada
    const selectedRoom = document.getElementById("rooms").value;
    console.log("🏁 Iniciando sala offline:", selectedRoom);

    // Inyectar mapa personalizado offline
game.mapSettings = offlineMapConfig;

// Si tenés funciones como loadMap o setField, llamalas acá
if (game.loadTilemap) {
    game.loadTilemap(offlineMapConfig.currentTilemap); // ← carga "tileMap.tmx"
}

if (game.setFieldSettings) {
    game.setFieldSettings(offlineMapConfig); // ← si hay función para setear todo junto
}

console.log("🗺️ Mapa offline cargado:", offlineMapConfig.currentTilemap);
};
